 17→public class SpacingAroundAngleBracketsRule : StandardRule("spacing-around-angle-brackets") {
 18→    override fun beforeVisitChildNodes(
 19→        node: ASTNode,
 20→        autoCorrect: Boolean,
 21→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 22→    ) {
 23→        if (node.elementType != TYPE_PARAMETER_LIST && node.elementType != TYPE_ARGUMENT_LIST) {
 24→            return
 25→        }
 26→
 27→        val openingBracket = node.firstChildNode
 28→        if (openingBracket != null) {
 29→            // Check for rogue spacing before an opening bracket, e.g. Map <String, Int>
 30→            val beforeLeftAngle = openingBracket.prevLeaf()
 31→            if (beforeLeftAngle?.elementType == WHITE_SPACE) {
 32→                // Ignore when the whitespace is preceded by certain keywords, e.g. fun <T> func(arg: T) {}
 33→                if (!ELEMENT_TYPES_ALLOWING_PRECEDING_WHITESPACE.contains(beforeLeftAngle.prevLeaf()?.elementType)) {
 34→                    emit(beforeLeftAngle.startOffset, "Unexpected spacing before \"<\"", true)
 35→                    if (autoCorrect) {
 36→                        beforeLeftAngle.treeParent.removeChild(beforeLeftAngle)
 37→                    }
 38→                }
 39→            }
 40→
 41→            // Check for rogue spacing after an opening bracket
 42→            val afterLeftAngle = openingBracket.nextLeaf()
 43→            if (afterLeftAngle?.elementType == WHITE_SPACE) {
 44→                if (afterLeftAngle.isWhiteSpaceWithoutNewline()) {
 45→                    // when spacing does not include any new lines, e.g. Map< String, Int>
 46→                    emit(afterLeftAngle.startOffset, "Unexpected spacing after \"<\"", true)
 47→                    if (autoCorrect) {
 48→                        afterLeftAngle.treeParent.removeChild(afterLeftAngle)
 49→                    }
 50→                } else {
 51→                    // when spacing contains at least one new line, e.g.
 52→                    // SomeGenericType<[whitespace]
 53→                    //
 54→                    //      String, Int, String>
 55→                    // gets converted to
 56→                    // SomeGenericType<
 57→                    //      String, Int, String>
 58→                    val newLineWithIndent = afterLeftAngle.text.trimBeforeLastLine()
 59→                    if (autoCorrect) {
 60→                        (afterLeftAngle as LeafElement).rawReplaceWithText(newLineWithIndent)
 61→                    }
 62→                }
 63→            }
 64→        }
 65→
 66→        val closingBracket = node.lastChildNode
 67→        if (closingBracket != null) {
 68→            val beforeRightAngle = closingBracket.prevLeaf()
 69→            // Check for rogue spacing before a closing bracket
 70→            if (beforeRightAngle?.elementType == WHITE_SPACE) {
 71→                if (beforeRightAngle.isWhiteSpaceWithoutNewline()) {
 72→                    // when spacing does not include any new lines, e.g. Map<String, Int >
 73→                    emit(beforeRightAngle.startOffset, "Unexpected spacing before \">\"", true)
 74→                    if (autoCorrect) {
 75→                        beforeRightAngle.treeParent.removeChild(beforeRightAngle)
 76→                    }
 77→                } else {
 78→                    // when spacing contains at least one new line, e.g.
 79→                    // SomeGenericType<String, Int, String[whitespace]
 80→                    //
 81→                    //      >
 82→                    // gets converted to
 83→                    // SomeGenericType<String, Int, String
 84→                    //      >
 85→                    val newLineWithIndent = beforeRightAngle.text.trimBeforeLastLine()
 86→                    if (autoCorrect) {
 87→                        (beforeRightAngle as LeafElement).rawReplaceWithText(newLineWithIndent)
 88→                    }
 89→                }
 90→            }
 91→        }
 92→    }
 93→
 94→    private fun String.trimBeforeLastLine() = this.substring(this.lastIndexOf('\n'))
 95→
 96→    private companion object {
 97→        val ELEMENT_TYPES_ALLOWING_PRECEDING_WHITESPACE = setOf(VAL_KEYWORD, VAR_KEYWORD, FUN_KEYWORD)
 98→    }
 99→}
