{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/SpacingAroundColonRuleAnnotationUseSiteTargetTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundColonRuleAnnotationUseSiteTargetTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given annotation use-site targets with spacing around the colon then do not allow it`() {
        val code =
            """
            @file :JvmName(\"Foo\")
            @file: JvmName(\"Foo\")
            @file : JvmName(\"Foo\")

            class Foo {
                @set :[Inject VisibleForTesting]
                @set: [Inject VisibleForTesting]
                @set : [Inject VisibleForTesting]
                var collaborator: Collaborator? = null
            }
            """.trimIndent()

        val formattedCode =
            """
            @file:JvmName(\"Foo\")
            @file:JvmName(\"Foo\")
            @file:JvmName(\"Foo\")

            class Foo {
                @set:[Inject VisibleForTesting]
                @set:[Inject VisibleForTesting]
                @set:[Inject VisibleForTesting]
                var collaborator: Collaborator? = null
            }
            """.trimIndent()

        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 7, "Unexpected spacing before \":\""),
                LintViolation(2, 7, "Unexpected spacing after \":\""),
                LintViolation(3, 7, "Unexpected spacing before \":\""),
                LintViolation(3, 8, "Unexpected spacing after \":\""),
                LintViolation(6, 10, "Unexpected spacing before \":\""),
                LintViolation(7, 10, "Unexpected spacing after \":\""),
                LintViolation(8, 10, "Unexpected spacing before \":\""),
                LintViolation(8, 11, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }
}
"}

