 22→    ) {
 23→        if (node.elementType != TYPE_PARAMETER_LIST && node.elementType != TYPE_ARGUMENT_LIST) {
 24→            return
 25→        }
 26→
 27→        val openingBracket = node.firstChildNode
 28→        if (openingBracket != null) {
 29→            // Check for rogue spacing before an opening bracket, e.g. Map <String, Int>
 30→            val beforeLeftAngle = openingBracket.prevLeaf()
 31→            if (beforeLeftAngle?.elementType == WHITE_SPACE) {
 32→                // Ignore when the whitespace is preceded by certain keywords, e.g. fun <T> func(arg: T) {}
 33→                if (!ELEMENT_TYPES_ALLOWING_PRECEDING_WHITESPACE.contains(beforeLeftAngle.prevLeaf()?.elementType)) {
 34→                    emit(beforeLeftAngle.startOffset, "Unexpected spacing before \"<\"", true)
 35→                    if (autoCorrect) {
 36→                        beforeLeftAngle.treeParent.removeChild(beforeLeftAngle)
 37→                    }
 38→                }
 39→            }
 40→
 41→            // Check for rogue spacing after an opening bracket
 42→            val afterLeftAngle = openingBracket.nextLeaf()
 43→            if (afterLeftAngle?.elementType == WHITE_SPACE) {
